count = 0
for old, new in fixes:
    if old in text:
        text = text.replace(old, new, 1)
        count += 1
        print(f"OK fix {count}: applied")
    else:
        # Try CRLF
        old_crlf = old.replace('\n', '\r\n')
        new_crlf = new.replace('\n', '\r\n')
        if old_crlf in text:
            text = text.replace(old_crlf, new_crlf, 1)
            count += 1
            print(f"OK fix {count}: applied (CRLF)")
        else:
            print(f"NOT FOUND: fix {count+1}: {old[:80]}...")

FILE.write_text(text, encoding='utf-8')
print(f"\n{count}/{len(fixes)} fixes applied")
